// app/payment-success/page.tsx
'use client';
import { useEffect, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Loader2, CheckCircle } from 'lucide-react';
import { supabase } from '@/lib/supabase';

function PaymentSuccessContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const memorialId = searchParams.get('id'); // Get ID from URL

    useEffect(() => {
        const finalizePayment = async () => {
            // 1. If we don't have an ID, we can't update anything
            if (!memorialId) {
                console.error("No memorial ID found in success URL");
                return;
            }

            console.log("Finalizing payment for memorial:", memorialId);

            // 2. Update Supabase: Set paid to true and status to published
            const { data, error } = await supabase
                .from('memorials')
                .update({
                    paid: true,
                    status: 'published'
                })
                .eq('id', memorialId)
                .select();

            if (error) {
                console.error("Database update failed:", error);
                alert("Payment was successful but we couldn't update your archive. Please contact support.");
            } else {
                console.log("Archive successfully updated to PAID state:", data);

                // 3. Clear the temporary ID from localStorage since we are done
                localStorage.removeItem('current-memorial-id');

                // 4. Redirect back to the Hub after 3 seconds
                setTimeout(() => {
                    router.push(`/create?id=${memorialId}`);
                }, 3000);
            }
        };

        finalizePayment();
    }, [memorialId, router]);

    return (
        <div className="min-h-screen bg-ivory flex items-center justify-center p-6">
            <div className="text-center max-w-md">
                <div className="w-20 h-20 bg-sage/10 rounded-full flex items-center justify-center mx-auto mb-6 animate-bounce">
                    <CheckCircle className="text-sage" size={40} />
                </div>
                <h1 className="font-serif text-4xl text-charcoal mb-4">Payment Successful</h1>
                <p className="text-charcoal/60 mb-8 leading-relaxed">
                    We are finalizing your eternal archive. Please wait a moment while we remove the watermarks...
                </p>
                <div className="flex items-center justify-center gap-2 text-sage font-medium">
                    <Loader2 className="animate-spin" size={20} />
                    <span>Redirecting to your Crossroads...</span>
                </div>
            </div>
        </div>
    );
}

export default function PaymentSuccessPage() {
    return (
        <Suspense fallback={<div>Loading...</div>}>
            <PaymentSuccessContent />
        </Suspense>
    );
}